```bash
python3 - << 'PY'
import io,sys,os,re,subprocess

path = "llvm/lib/Transforms/Vectorize/SLPVectorizer.cpp"
with open(path, 'r', encoding='utf-8') as f:
    txt = f.read()

changed = False

# Insert ensureDominatingIP method after destructor if not present
if "void ensureDominatingIP()" not in txt:
    anchor = "~ShuffleIRBuilder() = default;"
    ins = """~ShuffleIRBuilder() = default;
    /// Ensure the Builder insertion point is set to a dominating location
    /// within the current block to avoid dominance violations between
    /// created shuffle instructions.
    void ensureDominatingIP() {
      if (Builder.GetInsertBlock() && !Builder.GetInsertPoint().isSet()) {
        BasicBlock *BB = Builder.GetInsertBlock();
        Builder.SetInsertPoint(BB, BB->getFirstNonPHIIt());
      }
    }
"""
    if anchor in txt:
        txt = txt.replace(anchor, ins)
        changed = True

# Helper to inject ensureDominatingIP() after a function signature if missing
def inject_after_signature(text, signature):
    idx = text.find(signature)
    if idx == -1:
        return text, False
    body_start = idx + len(signature)
    # Skip any whitespace/newlines
    j = body_start
    while j < len(text) and text[j] in " \t\r\n":
        j += 1
    if text[j:j+23] == "ensureDominatingIP();":
        return text, False
    return text[:body_start] + "\n      ensureDominatingIP();" + text[body_start:], True

sigs = [
    "Value *createShuffleVector(Value *V1, Value *V2, ArrayRef<int> Mask) {",
    "Value *createShuffleVector(Value *V1, ArrayRef<int> Mask) {",
    "void resizeToMatch(Value *&V1, Value *&V2) {",
]

for sig in sigs:
    txt, ch = inject_after_signature(txt, sig)
    changed = changed or ch

if changed:
    with open(path, 'w', encoding='utf-8') as f:
        f.write(txt)

# Run submit-patch to build and validate
subprocess.run(["submit-patch"], check=False)
PY
